import Foundation

let emptyPath = IndexPath()
print(emptyPath.isEmpty)
let singlePath = IndexPath(index: 1)
print(singlePath.count)
var path = IndexPath(indexes: [2, 4])
print(path.count)
print(path.isEmpty)
path.append(6)
print(path.count)
let longer = path.appending(8)
print(longer.count)
print(path.count)

let emptySet = IndexSet()
print(emptySet.isEmpty)
print(emptySet.first == nil)
let singleSet = IndexSet(integer: 9)
print(singleSet.count)
let closedSet = IndexSet(integersIn: 3 ... 5)
print(closedSet.count)
print(closedSet.last)
var set = IndexSet(integersIn: 3 ..< 6)
print(set.count)
print(set.contains(4))
print(set.contains(8))
print(set.first)
print(set.last)
let inserted = set.insert(8)
print(inserted.inserted)
print(inserted.memberAfterInsert)
print(set.count)
let duplicate = set.insert(8)
print(duplicate.inserted)
print(duplicate.memberAfterInsert)
print(set.count)
